 12→// Constants
 13→// ---------------------------------------------------------------------------
 14→
 15→export const CLIENTS: ReadonlySet<string> = new Set(['codex', 'claude', 'gemini', 'doubao'])
 16→export const TEXT_BLOCK_TYPES: ReadonlySet<string> = new Set(['input_text', 'output_text', 'text'])
 17→export const SKIP_BLOCK_TYPES: ReadonlySet<string> = new Set(['thinking', 'reasoning'])
 18→export const TOOL_USE_TYPES: ReadonlySet<string> = new Set(['tool_use'])
 19→export const TOOL_RESULT_TYPES: ReadonlySet<string> = new Set(['tool_result'])
 20→
 21→const ALL_SKIP_TYPES: ReadonlySet<string> = new Set([
 22→  ...SKIP_BLOCK_TYPES, ...TOOL_USE_TYPES, ...TOOL_RESULT_TYPES,
 23→])
 24→
 25→// ---------------------------------------------------------------------------
 26→// Generic utilities
 27→// ---------------------------------------------------------------------------
 28→
 29→export function slugify(value: string, fallback = 'session'): string {
 30→  const asciiValue = value.replace(/[^\x00-\x7F]/g, '').toLowerCase()
 31→  const slug = asciiValue.replace(/[^a-z0-9._-]+/g, '-').replace(/^[-._]+|[-._]+$/g, '')
 32→  return slug || fallback
 33→}
 34→
 35→export function sha256File(filePath: string): string {
 36→  const data = readFileSync(filePath)
 37→  return createHash('sha256').update(data).digest('hex')
 38→}
 39→
 40→export function contentHash(text: string): string {
 41→  return createHash('sha256').update(text, 'utf8').digest('hex').slice(0, 16)
 42→}
 43→
 44→export function normalizeTimestamp(value: unknown, fallback?: string | null): string {
 45→  if (typeof value === 'number') {
 46→    // Always treat as Unix seconds (matching Python's datetime.fromtimestamp)
 47→    const d = new Date(value * 1000)
 48→    return formatUtcIso(d)
 49→  }
 50→
 51→  if (value instanceof Date) {
 52→    return formatUtcIso(value)
 53→  }
 54→
 55→  if (typeof value === 'string') {
 56→    const text = value.trim()
 57→    if (!text) {
 58→      return fallback ?? normalizeTimestamp(new Date())
 59→    }
 60→    const parsed = parseIsoTimestamp(text)
 61→    if (parsed !== null) {
 62→      return formatUtcIso(parsed)
 63→    }
 64→    return text
 65→  }
 66→
 67→  return fallback ?? normalizeTimestamp(new Date())
 68→}
 69→
 70→export function earliestTimestamp(current: string, candidate: unknown): string {
 71→  const normalized = normalizeTimestamp(candidate, current)
 72→  const currentDt = parseIsoTimestamp(current)
 73→  const normalizedDt = parseIsoTimestamp(normalized)
 74→  if (currentDt !== null && normalizedDt !== null) {
 75→    return normalizedDt < currentDt ? normalized : current
 76→  }
 77→  if (normalizedDt !== null) {
 78→    return normalized
 79→  }
 80→  return current || normalized
 81→}
 82→
 83→export function parseIsoTimestamp(value: string): Date | null {
 84→  if (!value) return null
 85→  let candidate = value
 86→  if (candidate.endsWith('Z')) {
 87→    candidate = candidate.slice(0, -1) + '+00:00'
 88→  } else if (!/[+-]\d{2}:\d{2}$/.test(candidate) && !/[+-]\d{4}$/.test(candidate)) {
 89→    // No timezone offset — treat as UTC (matching Python behavior)
 90→    candidate = candidate + '+00:00'
 91→  }
 92→  const d = new Date(candidate)
 93→  if (isNaN(d.getTime())) return null
 94→  return d
 95→}
 96→
 97→export function timestampPartition(timestamp: string): [string, string] {
 98→  const d = parseIsoTimestamp(timestamp)
 99→  if (d === null) return ['unknown', 'unknown']
100→  const year = d.getUTCFullYear().toString()
101→  const month = (d.getUTCMonth() + 1).toString().padStart(2, '0')
102→  return [year, month]
103→}
104→
105→export function joinParagraphs(parts: Iterable<string>): string {
106→  const cleaned: string[] = []
107→  for (const part of parts) {
108→    const trimmed = String(part).trim()
109→    if (trimmed) cleaned.push(trimmed)
110→  }
111→  return cleaned.join('\n\n')
112→}
113→
114→export function summarizeValue(value: unknown, limit = 180): string {
115→  if (value === null || value === undefined) return 'none'
116→  if (typeof value === 'string') {
117→    const text = value.replace(/\s+/g, ' ').trim()
118→    return truncate(text, limit)
119→  }
120→  let text: string
121→  try {
122→    text = JSON.stringify(sortKeysDeep(value))
123→  } catch {
124→    text = String(value)
125→  }
126→  text = text.replace(/\s+/g, ' ').trim()
127→  return truncate(text, limit)
128→}
129→
130→export function truncate(text: string, limit: number): string {
131→  return text.length <= limit ? text : text.slice(0, limit - 3) + '...'
132→}
