185→export function loadJson(filePath: string): Record<string, unknown> | null {
186→  if (!existsSync(filePath)) return null
187→  try {
188→    const text = readFileSync(filePath, 'utf-8')
189→    return JSON.parse(text) as Record<string, unknown>
190→  } catch {
191→    return null
192→  }
193→}
