346→function formatUtcIso(d: Date): string {
347→  const year = d.getUTCFullYear()
348→  const month = String(d.getUTCMonth() + 1).padStart(2, '0')
349→  const day = String(d.getUTCDate()).padStart(2, '0')
350→  const hours = String(d.getUTCHours()).padStart(2, '0')
351→  const minutes = String(d.getUTCMinutes()).padStart(2, '0')
352→  const seconds = String(d.getUTCSeconds()).padStart(2, '0')
353→  return `${year}-${month}-${day}T${hours}:${minutes}:${seconds}Z`
